import React, { useState, useEffect, useContext, useRef, useCallback } from 'react';
import { chatAPI, authAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';
import io from 'socket.io-client';

const ChatPage = () => {
  const { user } = useContext(AuthContext);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [unreadCounts, setUnreadCounts] = useState({});
  const [notificationText, setNotificationText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const socket = useRef(null);
  const messagesEndRef = useRef(null);
  const selectedUserRef = useRef(null);
  const usersRef = useRef([]);

  const handleReceiveMessage = useCallback((data) => {
    const activeUserId = selectedUserRef.current?._id;

    if (data.senderId === activeUserId) {
      setMessages((prev) => [...prev, data]);
      return;
    }

    setUnreadCounts((prev) => ({
      ...prev,
      [data.senderId]: (prev[data.senderId] || 0) + 1,
    }));

    const sender = usersRef.current.find((item) => item._id === data.senderId);
    setNotificationText(`New message from ${sender?.name || 'student'}`);
  }, []);

  useEffect(() => {
    socket.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socket.current.emit('user_join', user?._id);
    socket.current.on('receive_message', handleReceiveMessage);

    return () => {
      socket.current.off('receive_message', handleReceiveMessage);
      socket.current.disconnect();
    };
  }, [user, handleReceiveMessage]);

  useEffect(() => {
    selectedUserRef.current = selectedUser;
  }, [selectedUser]);

  useEffect(() => {
    usersRef.current = users;
  }, [users]);

  useEffect(() => {
    if (!notificationText) return undefined;
    const timer = setTimeout(() => setNotificationText(''), 3000);
    return () => clearTimeout(timer);
  }, [notificationText]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    fetchUsers();
  }, []);

  const filteredUsers = users.filter((student) => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return true;
    return (
      student.name?.toLowerCase().includes(query) ||
      student.email?.toLowerCase().includes(query)
    );
  });

  const fetchUsers = async () => {
    try {
      const res = await authAPI.getAllStudents();
      setUsers(res.data.students || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch users');
    }
  };

  const handleSelectUser = async (student) => {
    setSelectedUser(student);
    setUnreadCounts((prev) => ({ ...prev, [student._id]: 0 }));
    setLoading(true);
    try {
      const res = await chatAPI.getChatHistory(student._id);
      setMessages(res.data.messages || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch chat history');
    } finally {
      setLoading(false);
    }
  };

  const handleSendMessage = async () => {
    if (!newMessage.trim() || !selectedUser) return;

    try {
      await chatAPI.sendMessage({
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      socket.current.emit('send_message', {
        senderId: user._id,
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      setMessages((prev) => [
        ...prev,
        {
          senderId: user._id,
          senderName: user.name,
          message: newMessage.trim(),
          timestamp: new Date().toISOString(),
        },
      ]);
      setNewMessage('');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to send message');
    }
  };

  const formatTime = (timestamp) =>
    new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container-fluid">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Messages</span>
          <h1 className="portal-page-title">Student Conversations</h1>
          <p className="portal-page-subtitle">
            Keep communication organized and respond to student questions in one workspace.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {notificationText && (
          <div className="position-fixed top-0 end-0 p-3" style={{ zIndex: 1080 }}>
            <div className="alert alert-info shadow-sm mb-0" role="alert">
              {notificationText}
            </div>
          </div>
        )}

        <div className="card portal-chat-shell shadow-sm">
          <div className="row g-0 h-100">
            <div className="col-md-4 col-lg-3 portal-chat-sidebar">
              <div className="portal-chat-toolbar">
                <div>
                  <div className="portal-stat-label">Inbox</div>
                  <h5 className="mb-0 fw-bold">Students</h5>
                </div>
                <input
                  type="text"
                  className="form-control portal-chat-search"
                  placeholder="Search"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <div className="portal-chat-list" style={{ height: '540px' }}>
                {filteredUsers.length === 0 ? (
                  <div className="portal-empty-state">No student conversations yet.</div>
                ) : (
                  filteredUsers.map((student) => (
                    <button
                      key={student._id}
                      className={`portal-chat-user ${selectedUser?._id === student._id ? 'active' : ''}`}
                      onClick={() => handleSelectUser(student)}
                    >
                      <div className="fw-bold d-flex justify-content-between align-items-center">
                        <span>{student.name}</span>
                        {unreadCounts[student._id] > 0 && (
                          <span className="badge bg-danger rounded-pill">{unreadCounts[student._id]}</span>
                        )}
                      </div>
                      <small className="text-muted">{student.email}</small>
                    </button>
                  ))
                )}
              </div>
            </div>

            <div className="col-md-8 col-lg-9 d-flex flex-column portal-chat-main">
              {selectedUser ? (
                <>
                  <div className="portal-chat-header p-3">
                    <div className="d-flex justify-content-between align-items-start gap-3 flex-wrap">
                      <div>
                        <h5 className="mb-1">{selectedUser.name}</h5>
                        <small>{selectedUser.email}</small>
                      </div>
                      <span className="portal-chat-status">Conversation active</span>
                    </div>
                  </div>

                  <div className="flex-grow-1 p-3 portal-chat-messages" style={{ height: '450px' }}>
                    {loading ? (
                      <div className="text-center py-5">
                        <div className="spinner-border text-primary" role="status">
                          <span className="visually-hidden">Loading...</span>
                        </div>
                      </div>
                    ) : messages.length === 0 ? (
                      <div className="portal-empty-state">No messages yet. Start the conversation.</div>
                    ) : (
                      messages.map((msg, index) => (
                        <div
                          key={index}
                          className={`d-flex mb-3 ${
                            msg.senderId === user._id ? 'justify-content-end' : 'justify-content-start'
                          }`}
                        >
                          <div className={`portal-message ${msg.senderId === user._id ? 'outgoing' : 'incoming'}`}>
                            <div>{msg.message}</div>
                            <small className="portal-message-time">{formatTime(msg.timestamp)}</small>
                          </div>
                        </div>
                      ))
                    )}
                    <div ref={messagesEndRef} />
                  </div>

                  <div className="portal-chat-input p-3">
                    <div className="portal-message-composer">
                      <input
                        type="text"
                        className="form-control"
                        placeholder="Type your message..."
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                      />
                      <button className="btn btn-primary px-4" type="button" onClick={handleSendMessage}>
                        Send
                      </button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="portal-empty-state">Select a student to open the conversation.</div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatPage;
